#!/bin/bash

# Bundle Size Check Script
# Checks iOS app bundle size and warns if it exceeds thresholds
# Usage: ./scripts/check-bundle-size.sh [configuration]

set -e

CONFIGURATION="${1:-Release}"
SCHEME="FIN1"
PROJECT="FIN1.xcodeproj"
DESTINATION="platform=iOS Simulator,name=iPhone 16,OS=18.6"

# Size thresholds (in MB)
WARNING_THRESHOLD=50   # Warn if bundle exceeds 50MB
ERROR_THRESHOLD=100     # Error if bundle exceeds 100MB
CRITICAL_THRESHOLD=180  # Critical if bundle exceeds 180MB (near App Store limit)

# Colors for output
RED='\033[0;31m'
YELLOW='\033[1;33m'
GREEN='\033[0;32m'
NC='\033[0m' # No Color

echo "📦 Checking bundle size for configuration: $CONFIGURATION"
echo ""

# Build the app
echo "🔨 Building app..."
xcodebuild -project "$PROJECT" \
    -scheme "$SCHEME" \
    -configuration "$CONFIGURATION" \
    -destination "$DESTINATION" \
    -quiet \
    build

# Find the built app
APP_PATH=$(find build -name "*.app" -type d -path "*$CONFIGURATION*" | head -1)

if [ -z "$APP_PATH" ]; then
    echo "❌ Error: Could not find built app in build directory"
    exit 1
fi

# Get bundle size in MB
BUNDLE_SIZE_MB=$(du -sm "$APP_PATH" | cut -f1)
BUNDLE_SIZE_BYTES=$(du -sb "$APP_PATH" | cut -f1)

